1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	const LOYALTY_THRESHOLD_YEARS = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES = 1;
20	const FOLLOWUP_DISCOUNT_RATE = 0.15;
21	
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const DEDUCTIBLE_PER_ITEM = 100;
26	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	
29	export function claim(input: { policy: { items: { type: string; material?: string; enchantment?: number }[] }; incident: { cause?: string; damages: { itemType: string; amount: number }[] } }): number {
30	  const damages = input.incident.damages;
31	  const policyItems = input.policy.items;
32	  const totalPayout = damages.reduce((payoutSoFar, damage) => {
33	    if (damage.amount < 0) {
34	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
35	    }
36	    const policyItem = policyItems.find((item) => item.type === damage.itemType);
37	    if (policyItem === undefined) {
38	      throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
39	    }
40	    const hasHighEnchantment = (policyItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
41	    const reimbursable = hasHighEnchantment ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE : damage.amount;
42	    return payoutSoFar + (reimbursable - DEDUCTIBLE_PER_ITEM);
43	  }, 0);
44	  return Math.floor(totalPayout);
45	}
46	
47	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[]; previousQuoteCount?: number }): number {
48	  const items = input.items;
49	  for (const item of items) {
50	    if (!(item.type in BASE_PRICE_BY_TYPE)) {
51	      throw new Error(`Unknown item type: ${item.type}`);
52	    }
53	  }
54	  const countByType: Record<string, number> = {};
55	  for (const item of items) {
56	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
57	  }
58	  let basePrice = 0;
59	  for (const type of Object.keys(countByType)) {
60	    const count = countByType[type];
61	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
62	    if (formsRuneBlock) {
63	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
64	    } else {
65	      basePrice += count * BASE_PRICE_BY_TYPE[type];
66	    }
67	  }
68	  let highEnchantmentSurcharges = 0;
69	  let cursedSurcharges = 0;
70	  for (const item of items) {
71	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
72	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
73	    }
74	    if (item.cursed === true) {
75	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
76	    }
77	  }
78	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
79	  const qualifiesForLoyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
80	  const loyaltyDiscount = qualifiesForLoyaltyDiscount ? basePrice * LOYALTY_DISCOUNT_RATE : 0;
81	  const qualifiesForFollowUpDiscount = (input.previousQuoteCount ?? 0) >= FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES;
82	  const followUpDiscount = qualifiesForFollowUpDiscount ? basePrice * FOLLOWUP_DISCOUNT_RATE : 0;
83	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
84	  return Math.ceil(premium);
85	}
